import{_ as n,o as a,c as t,a2 as o}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"DeerFlow Agentic Loop","description":"","frontmatter":{"title":"DeerFlow Agentic Loop","status":"complete"},"headers":[],"relativePath":"research/agents/deer-flow/agentic-loop.md","filePath":"research/agents/deer-flow/agentic-loop.md"}'),e={name:"research/agents/deer-flow/agentic-loop.md"};function l(p,s,r,c,i,y){return a(),t("div",null,[...s[0]||(s[0]=[o(`<h1 id="deerflow-agentic-loop" tabindex="-1">DeerFlow Agentic Loop <a class="header-anchor" href="#deerflow-agentic-loop" aria-label="Permalink to &quot;DeerFlow Agentic Loop&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>DeerFlow&#39;s agentic loop is implemented as a <strong>LangGraph state graph</strong> — a directed graph where nodes are Python functions and edges are conditional routing decisions. The loop is explicitly typed (via Pydantic models), checkpointed (durable execution), and streaming (token-by-token output via SSE).</p><p>Unlike single-agent loops (Claude Code, Aider), DeerFlow&#39;s loop is two-level:</p><ol><li><strong>Outer loop</strong>: Lead agent orchestrates the overall task</li><li><strong>Inner loop</strong>: Each sub-agent runs its own isolated mini-loop</li></ol><hr><h2 id="execution-modes" tabindex="-1">Execution Modes <a class="header-anchor" href="#execution-modes" aria-label="Permalink to &quot;Execution Modes&quot;">​</a></h2><p>The loop&#39;s behavior is controlled by the execution mode, selected per-message:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Planning</th><th>Sub-Agents</th><th>Behavior</th></tr></thead><tbody><tr><td><strong>flash</strong></td><td>No</td><td>No</td><td>Direct researcher → reporter path; minimal reasoning</td></tr><tr><td><strong>standard</strong></td><td>No</td><td>No</td><td>Full coordinator → researcher → reporter; no parallelism</td></tr><tr><td><strong>pro</strong></td><td>Yes</td><td>No</td><td>Adds planner node; coordinator decomposes task first</td></tr><tr><td><strong>ultra</strong></td><td>Yes</td><td>Yes</td><td>Full fan-out; sub-agents run in parallel</td></tr></tbody></table><hr><h2 id="lead-agent-loop-pseudocode" tabindex="-1">Lead Agent Loop (Pseudocode) <a class="header-anchor" href="#lead-agent-loop-pseudocode" aria-label="Permalink to &quot;Lead Agent Loop (Pseudocode)&quot;">​</a></h2><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Simplified representation of the LangGraph state graph</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">State </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;messages&quot;</span><span style="color:#9399B2;">:</span><span style="color:#EBA0AC;font-style:italic;"> list</span><span style="color:#9399B2;">[</span><span style="color:#EBA0AC;font-style:italic;">Message</span><span style="color:#9399B2;">],</span><span style="color:#6C7086;font-style:italic;">      # conversation history</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;plan&quot;</span><span style="color:#9399B2;">:</span><span style="color:#CDD6F4;"> Plan </span><span style="color:#94E2D5;">|</span><span style="color:#CBA6F7;"> None</span><span style="color:#9399B2;">,</span><span style="color:#6C7086;font-style:italic;">            # task decomposition (pro/ultra modes)</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;sub_results&quot;</span><span style="color:#9399B2;">:</span><span style="color:#EBA0AC;font-style:italic;"> list</span><span style="color:#9399B2;">[</span><span style="color:#EBA0AC;font-style:italic;">Result</span><span style="color:#9399B2;">],</span><span style="color:#6C7086;font-style:italic;">    # collected from sub-agents</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;context&quot;</span><span style="color:#9399B2;">:</span><span style="color:#CDD6F4;"> AgentContext</span><span style="color:#9399B2;">,</span><span style="color:#6C7086;font-style:italic;">        # mode, thinking_enabled, etc.</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;memory&quot;</span><span style="color:#9399B2;">:</span><span style="color:#CDD6F4;"> UserMemory</span><span style="color:#9399B2;">,</span><span style="color:#6C7086;font-style:italic;">           # persistent cross-session data</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">def</span><span style="color:#89B4FA;font-style:italic;"> coordinator</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">state</span><span style="color:#9399B2;">:</span><span style="color:#EBA0AC;"> State</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> -&gt;</span><span style="color:#CDD6F4;"> Command</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;&quot;&quot;Decides whether to plan, research directly, or respond.&quot;&quot;&quot;</span></span>
<span class="line"><span style="color:#CBA6F7;">    if</span><span style="color:#CDD6F4;"> state</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">context</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">is_plan_mode</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CBA6F7;">        return</span><span style="color:#89B4FA;"> Command</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">goto</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;planner&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CBA6F7;">    if</span><span style="color:#CDD6F4;"> state</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">context</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">subagent_enabled </span><span style="color:#CBA6F7;">and</span><span style="color:#89B4FA;"> task_is_complex</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">state</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#CBA6F7;">        return</span><span style="color:#89B4FA;"> Command</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">goto</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;planner&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CBA6F7;">    return</span><span style="color:#89B4FA;"> Command</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">goto</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;researcher&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">def</span><span style="color:#89B4FA;font-style:italic;"> planner</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">state</span><span style="color:#9399B2;">:</span><span style="color:#EBA0AC;"> State</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> -&gt;</span><span style="color:#CDD6F4;"> State</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;&quot;&quot;Decomposes task into structured sub-tasks (pro/ultra modes).&quot;&quot;&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">    plan </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> llm</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">invoke</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">PLANNER_PROMPT</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> state</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">messages</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CBA6F7;">    return</span><span style="color:#9399B2;"> {</span><span style="color:#94E2D5;">**</span><span style="color:#CDD6F4;">state</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;plan&quot;</span><span style="color:#9399B2;">:</span><span style="color:#CDD6F4;"> plan</span><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">def</span><span style="color:#89B4FA;font-style:italic;"> researcher</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">state</span><span style="color:#9399B2;">:</span><span style="color:#EBA0AC;"> State</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> -&gt;</span><span style="color:#CDD6F4;"> State</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;&quot;&quot;Core tool-use loop: search, fetch, bash, files.&quot;&quot;&quot;</span></span>
<span class="line"><span style="color:#CBA6F7;">    while</span><span style="color:#CBA6F7;"> not</span><span style="color:#89B4FA;"> task_complete</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">state</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#CDD6F4;">        response </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> llm</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">invoke_with_tools</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">state</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">messages</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> TOOLS</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CBA6F7;">        if</span><span style="color:#CDD6F4;"> response</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">tool_calls</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CDD6F4;">            results </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;"> execute_tools</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">response</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">tool_calls</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> sandbox</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CDD6F4;">            state </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;"> append_tool_results</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">state</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> results</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CBA6F7;">        if</span><span style="color:#CDD6F4;"> response</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">is_final</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CBA6F7;">            break</span></span>
<span class="line"><span style="color:#CBA6F7;">        if</span><span style="color:#89B4FA;"> context_near_limit</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">state</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#CDD6F4;">            state </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;"> summarize_completed_subtasks</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">state</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CBA6F7;">    return</span><span style="color:#CDD6F4;"> state</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">def</span><span style="color:#89B4FA;font-style:italic;"> sub_agent_spawner</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">state</span><span style="color:#9399B2;">:</span><span style="color:#EBA0AC;"> State</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> -&gt;</span><span style="color:#CDD6F4;"> State</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;&quot;&quot;Ultra mode: spawns sub-agents in parallel for each plan step.&quot;&quot;&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">    sub_tasks </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> state</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">plan</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">steps</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    # LangGraph&#39;s Send() primitive for parallel dispatch</span></span>
<span class="line"><span style="color:#CBA6F7;">    return</span><span style="color:#9399B2;"> [</span><span style="color:#89B4FA;">Send</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;sub_agent&quot;</span><span style="color:#9399B2;">,</span><span style="color:#9399B2;"> {</span><span style="color:#A6E3A1;">&quot;task&quot;</span><span style="color:#9399B2;">:</span><span style="color:#CDD6F4;"> t</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;context&quot;</span><span style="color:#9399B2;">:</span><span style="color:#CDD6F4;"> state</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">context</span><span style="color:#9399B2;">})</span></span>
<span class="line"><span style="color:#CBA6F7;">            for</span><span style="color:#CDD6F4;"> t </span><span style="color:#CBA6F7;">in</span><span style="color:#CDD6F4;"> sub_tasks</span><span style="color:#9399B2;">]</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">def</span><span style="color:#89B4FA;font-style:italic;"> sub_agent</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">state</span><span style="color:#9399B2;">:</span><span style="color:#EBA0AC;"> SubAgentState</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> -&gt;</span><span style="color:#CDD6F4;"> SubAgentState</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;&quot;&quot;Isolated mini-loop: own context, own tools, own termination.&quot;&quot;&quot;</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    # Runs identically to researcher() but in isolated subgraph</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    # Cannot see parent context or sibling sub-agents</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    # Returns structured SubAgentResult on completion</span></span>
<span class="line"><span style="color:#CDD6F4;">    ...</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">def</span><span style="color:#89B4FA;font-style:italic;"> reporter</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">state</span><span style="color:#9399B2;">:</span><span style="color:#EBA0AC;"> State</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> -&gt;</span><span style="color:#CDD6F4;"> State</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;&quot;&quot;Synthesizes all results into final output.&quot;&quot;&quot;</span></span>
<span class="line"><span style="color:#CBA6F7;">    if</span><span style="color:#CDD6F4;"> state</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">sub_results</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">        # Merge parallel sub-agent results</span></span>
<span class="line"><span style="color:#CDD6F4;">        synthesis </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> llm</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">invoke</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">REPORTER_PROMPT</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> state</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">sub_results</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CBA6F7;">    else</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CDD6F4;">        synthesis </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> llm</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">invoke</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">REPORTER_PROMPT</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> state</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">messages</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    # Output may be: text report, slide deck, web page, code, etc.</span></span>
<span class="line"><span style="color:#CBA6F7;">    return</span><span style="color:#9399B2;"> {</span><span style="color:#94E2D5;">**</span><span style="color:#CDD6F4;">state</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;messages&quot;</span><span style="color:#9399B2;">:</span><span style="color:#9399B2;"> [</span><span style="color:#94E2D5;">*</span><span style="color:#CDD6F4;">state</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">messages</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> synthesis</span><span style="color:#9399B2;">]}</span></span></code></pre></div><hr><h2 id="sub-agent-architecture" tabindex="-1">Sub-Agent Architecture <a class="header-anchor" href="#sub-agent-architecture" aria-label="Permalink to &quot;Sub-Agent Architecture&quot;">​</a></h2><p>Sub-agents are the key differentiator in ultra mode:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Lead Agent (coordinator/planner/reporter)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── Sub-Agent 1 (isolated context)</span></span>
<span class="line"><span>    │   ├── Task: &quot;Research market size of X&quot;</span></span>
<span class="line"><span>    │   ├── Tools: web_search, web_fetch, file_write</span></span>
<span class="line"><span>    │   └── Returns: SubAgentResult{summary, sources, files}</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── Sub-Agent 2 (isolated context)</span></span>
<span class="line"><span>    │   ├── Task: &quot;Find competitors for X&quot;</span></span>
<span class="line"><span>    │   ├── Tools: web_search, web_fetch, file_write</span></span>
<span class="line"><span>    │   └── Returns: SubAgentResult{summary, sources, files}</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    └── Sub-Agent N (isolated context)</span></span>
<span class="line"><span>        ├── Task: &quot;Analyze financial data for X&quot;</span></span>
<span class="line"><span>        ├── Tools: web_search, bash, file_read, file_write</span></span>
<span class="line"><span>        └── Returns: SubAgentResult{summary, files, charts}</span></span></code></pre></div><p><strong>Key design decisions:</strong></p><ol><li><strong>Isolated context per sub-agent</strong> — sub-agents cannot see each other or the lead agent&#39;s context. Prevents distraction and context pollution.</li><li><strong>Scoped tools</strong> — each sub-agent gets only the tools it needs for its task.</li><li><strong>Termination conditions</strong> — explicit stop criteria prevent runaway sub-agents.</li><li><strong>Parallel execution</strong> — LangGraph&#39;s <code>Send()</code> primitive dispatches sub-agents concurrently when possible.</li><li><strong>Structured results</strong> — sub-agents return typed <code>SubAgentResult</code> objects, not raw text. The reporter receives clean, structured data.</li></ol><p><strong>What sub-agents share with the lead agent:</strong></p><ul><li>Sandbox filesystem (read/write to <code>/mnt/user-data/workspace/</code>)</li><li>Skill definitions (can load and follow skills)</li><li>Memory (read-only; cannot mutate)</li><li>Model configuration</li></ul><p><strong>What sub-agents do NOT share:</strong></p><ul><li>Message history (completely isolated)</li><li>Tool call history</li><li>Intermediate reasoning</li></ul><hr><h2 id="tool-execution-in-the-loop" tabindex="-1">Tool Execution in the Loop <a class="header-anchor" href="#tool-execution-in-the-loop" aria-label="Permalink to &quot;Tool Execution in the Loop&quot;">​</a></h2><p>Tools run inside the sandbox container. The loop dispatches tool calls and collects results:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Researcher node</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── LLM produces ToolCall(name=&quot;web_search&quot;, args={query: &quot;...&quot;})</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── Tool dispatcher routes to sandbox execution</span></span>
<span class="line"><span>    │   ├── web_search → Tavily/InfoQuest API</span></span>
<span class="line"><span>    │   ├── web_fetch  → HTTP fetch in sandbox</span></span>
<span class="line"><span>    │   ├── bash       → Execute in Docker container</span></span>
<span class="line"><span>    │   └── file_*     → Read/write /mnt/user-data/workspace/</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    └── ToolResult returned to message history</span></span></code></pre></div><hr><h2 id="context-management-in-the-loop" tabindex="-1">Context Management in the Loop <a class="header-anchor" href="#context-management-in-the-loop" aria-label="Permalink to &quot;Context Management in the Loop&quot;">​</a></h2><p>DeerFlow manages context pressure within the researcher loop:</p><ol><li><strong>Skill progressive loading</strong> — skills load only when the task needs them; not at loop start</li><li><strong>Sub-task summarization</strong> — completed sub-tasks are summarized and their raw content removed</li><li><strong>Filesystem offload</strong> — intermediate results written to <code>/mnt/workspace/</code> rather than kept in context</li><li><strong>Sub-agent isolation</strong> — parallel work happens in separate context windows; only structured summaries return to lead</li></ol><p>See <a href="./context-management.html">context-management.md</a> for details.</p><hr><h2 id="streaming" tabindex="-1">Streaming <a class="header-anchor" href="#streaming" aria-label="Permalink to &quot;Streaming&quot;">​</a></h2><p>DeerFlow streams responses token-by-token via <strong>Server-Sent Events (SSE)</strong>:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>LangGraph Server (port 2024)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    └── /stream endpoint</span></span>
<span class="line"><span>        ├── Emits: {&quot;type&quot;: &quot;message_chunk&quot;, &quot;content&quot;: &quot;...&quot;}</span></span>
<span class="line"><span>        ├── Emits: {&quot;type&quot;: &quot;tool_call&quot;, &quot;name&quot;: &quot;web_search&quot;, ...}</span></span>
<span class="line"><span>        ├── Emits: {&quot;type&quot;: &quot;tool_result&quot;, &quot;content&quot;: &quot;...&quot;}</span></span>
<span class="line"><span>        ├── Emits: {&quot;type&quot;: &quot;sub_agent_start&quot;, &quot;task&quot;: &quot;...&quot;}</span></span>
<span class="line"><span>        └── Emits: {&quot;type&quot;: &quot;done&quot;}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Frontend (port 3000)</span></span>
<span class="line"><span>    └── EventSource → incremental rendering in Next.js UI</span></span></code></pre></div><p>The IM channel gateway also streams responses back to Telegram/Slack/Feishu in real-time.</p><hr><h2 id="comparison-with-other-agents-in-this-research" tabindex="-1">Comparison with Other Agents in This Research <a class="header-anchor" href="#comparison-with-other-agents-in-this-research" aria-label="Permalink to &quot;Comparison with Other Agents in This Research&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aspect</th><th>DeerFlow</th><th>Claude Code</th><th>ForgeCode</th><th>SageAgent</th></tr></thead><tbody><tr><td>Loop implementation</td><td>LangGraph graph</td><td>Custom TypeScript</td><td>Custom (ZSH-native)</td><td>Custom Python</td></tr><tr><td>Sub-agent spawning</td><td>Dynamic, on-the-fly</td><td>Static task types</td><td>Static 3-agent</td><td>Static 5-agent pipeline</td></tr><tr><td>Sub-agent isolation</td><td>Full context isolation</td><td>Full context isolation</td><td>Summary-only handoff</td><td>Summary handoff</td></tr><tr><td>Parallel execution</td><td>Yes (Send primitive)</td><td>No (sequential)</td><td>No</td><td>No</td></tr><tr><td>Execution modes</td><td>4 (flash→ultra)</td><td>3 (default/plan/agent)</td><td>1</td><td>1</td></tr><tr><td>Streaming</td><td>SSE token-by-token</td><td>SSE token-by-token</td><td>Terminal streaming</td><td>No</td></tr><tr><td>Sandbox</td><td>Docker container</td><td>Host process</td><td>Host shell</td><td>Host process</td></tr><tr><td>Checkpointing</td><td>Yes (LangGraph)</td><td>No</td><td>No</td><td>No</td></tr></tbody></table>`,39)])])}const h=n(e,[["render",l]]);export{u as __pageData,h as default};
